mapper.select:
select distinct objectid as objectId, objectName, tableName, tableId, objectState, dataSourceCode, sjzybq1, sjzybq2, sjzybq3, sjzybq4, sjzybq5, sjzybq6, trim(dataSourceCh) as dataSourceCh, createTime, case when creator is null then '' else trim(creator) end as creator, case when updater is null then '' else trim(updater) end as updater, updateTime, dataOrganizationClassify, dataSourceClassify from (select distinct o.objectid, c.sjxjbm as tableId, c.sjxjzwmc as objectName, c.tablename as tableName, c.sjzybq1, c.sjzybq2, c.sjzybq3, c.sjzybq4, c.sjzybq5, c.sjzybq6, case when c.objectstate is null then -1 else c.objectstate end as objectState, o.data_source as dataSourceCode, s.valtext as dataSourceCh, case when o.createtime is null then '' else to_char(o.createtime, 'yyyy-mm-dd HH24:mi:ss') end as createTime, o.creator as creator, o.updater as updater, case when o.updatetime is null then '' else to_char(o.updatetime, 'yyyy-mm-dd HH24:mi:ss') end as updateTime, case when c.secondaryorganizationch is null or c.secondaryorganizationch = '' then c.primaryorganizationch else c.primaryorganizationch || '->' || c.firstorganizationch || '->' || c.secondaryorganizationch end as dataOrganizationClassify, case when c.secondarydatasourcech is null then c.primarydatasourcech else c.primarydatasourcech || '->' || c.secondarydatasourcech end as dataSourceClassify from classify_interface_all_date c right join (select * from synlte.object where deleted = 0 and upper(relate_tablename) = 'OBJECTFIELD'
and (upper(objectname) like upper('%${summaryQueryParams.searchCode}%') or upper(tablename) like upper('%${summaryQueryParams.searchCode}%') or upper(tableid) like upper('%${summaryQueryParams.searchCode}%'))
and sjzybq1 in
#{item}
and sjzybq2 in
#{item}
and sjzybq3 in
#{item}
and sjzybq4 in
#{item}
and sjzybq5 in
#{item}
and sjzybq6 in
#{item}
and objectstate in
#{item}
and (0, objectid) in
(0, #{item})
) o on upper(c.sjxjbm) = upper(o.tableid) left join (select distinct valtext, valvalue from synlte.fieldcodeval where codeid = 'JZCODE0024') s on upper(o.data_source) = upper(s.valvalue)) x
and x.dataorganizationclassify in
#{item}
and x.datasourceclassify in
#{item}
order by ${summaryQueryParams.sort}
${summaryQueryParams.sortOrder}

select distinct tablename from CLASSIFY_INTERFACE_ALL_DATE

    sjxjbm is not null

        and  PRIMARYORGANIZATIONCH = #{firstValue}


        and SECONDARYORGANIZATIONCH = #{secondaryClassifyValue}


        and THREEORGANIZATIONCH = #{threeClassifyValue}


        and upper(tablename) LIKE upper('%'||#{condition}||'%')

select.if:
select v3.codename as codeName from v_classify_info v1 left join v_classify_info v2 on v1.codeid = v2.parcodeid left join v_classify_info v3 on v3.parcodeid = v2.codeid
v1.codetext = '数据来源分类' and rownum =1
and v3.codetext = #{midClassType}

select v2.codename as codeName from v_classify_info v1 left join v_classify_info v2 on v1.codeid = v2.parcodeid
v1.codetext = '数据来源分类' and rownum =1
and v2.codetext = #{midClassType}

mapper.select:
select distinct PRIMARYORGANIZATIONCH || SECONDARYORGANIZATIONCH, '1' as mainClassifyId, '数据组织分类' as mainClassifyCh, SJYJFL as primaryClassifyId, PRIMARYORGANIZATIONCH as primaryClassifyCh, SJEJFL as secondaryClassifyId, SECONDARYORGANIZATIONCH as secondaryClassifyCh from CLASSIFY_INTERFACE_ALL_DATE where SJXJBM is not null
and PRIMARYORGANIZATIONCH = #{primaryClassifyCh}
order by sjyjfl

select tableid as tableId, objectId as objectId, SOURCEID as sourceId, tablename as objectEnglishName, objectname as objectChineseName, updatetime as modDate, case when SECONDARYDATASOURCECH is null then primarydatasourcech else primarydatasourcech || '->' || SECONDARYDATASOURCECH end as dataSourceClassify from (select distinct o.*, case when sourceParVci.CODETEXT is null then '中间表' else sourceParVci.CODETEXT end as PRIMARYDATASOURCECH, case when (sourceVci.CODETEXT is null and sourceParVci.CODETEXT is null) then '中间表' when (sourceVci.CODETEXT is null and sourceParVci.CODETEXT is not null) then '' else sourceVci.CODETEXT end as SECONDARYDATASOURCECH from (select o.* from (select objectId, SOURCEID, tablename, objectname, tableid, updatetime, SJZYLYLXVALUE from synlte.object where DELETED = 0 and upper(relate_tablename) = 'OBJECTFIELD') o where exists (select 1 from (select sjxjbm from classify_interface_all_date where SJEJFLCODENAME = '0191' or SJYJFLCODENAME = '04') cd where cd.sjxjbm = o.tableid)) o left join v_classify_info sourceVci on upper(sourceVci.codename) = upper(o.SJZYLYLXVALUE) and sourceVci.root = 'GACODE000404' left join v_classify_info sourceParVci on upper(sourceParVci.codeid) = upper(sourceVci.parcodeid))
(upper(objectname) like upper(concat('%',concat(#{searchText},'%'))) or upper(tableName) like upper(concat('%',concat(#{searchText},'%'))) or upper(tableId) like upper(concat('%',concat(#{searchText},'%'))) or upper(sourceId) like upper(concat('%',concat(#{searchText},'%'))) )
order by ${sort} ${sortOrder}
